 Begin CmpMap 	# Compound Mapping
    Nin = 3 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    MapA = 	# First component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 3 	# Number of input coordinates
          IsSimp = 1 	# Mapping has been simplified
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# First component Mapping
             Begin WinMap 	# Map one window on to another
                Nin = 3 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Sft1 = 0.00029088820866572201 	# Shift for axis 1
                Scl1 = -2.9088820866572201e-05 	# Scale factor for axis 1
                Sft2 = -0.00030525452453568163 	# Shift for axis 2
                Scl2 = 2.9088820866572201e-05 	# Scale factor for axis 2
                Sft3 = 372689488787.06067 	# Shift for axis 3
                Scl3 = -61037.210815429986 	# Scale factor for axis 3
             End WinMap
          MapB = 	# Second component Mapping
             Begin CmpMap 	# Compound Mapping
                Nin = 3 	# Number of input coordinates
                IsSimp = 1 	# Mapping has been simplified
             IsA Mapping 	# Mapping between coordinate systems
                Series = 0 	# Component Mappings applied in parallel
                MapA = 	# First component Mapping
                   Begin CmpMap 	# Compound Mapping
                      Nin = 2 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      InvA = 1 	# First Mapping used in inverse direction
                      MapA = 	# First component Mapping
                         Begin WcsMap 	# FITS-WCS sky projection
                            Nin = 2 	# Number of input coordinates
                         IsA Mapping 	# Mapping between coordinate systems
                            Type = "TAN" 	# Gnomonic projection
                         End WcsMap
                      MapB = 	# Second component Mapping
                         Begin CmpMap 	# Compound Mapping
                            Nin = 2 	# Number of input coordinates
                            IsSimp = 1 	# Mapping has been simplified
                         IsA Mapping 	# Mapping between coordinate systems
                            InvA = 1 	# First Mapping used in inverse direction
                            MapA = 	# First component Mapping
                               Begin SphMap 	# Cartesian to Spherical mapping
                                  Nin = 3 	# Number of input coordinates
                                  Nout = 2 	# Number of output coordinates
                               IsA Mapping 	# Mapping between coordinate systems
                                  UntRd = 1 	# All input vectors have unit length
                                  PlrLg = 0 	# Polar longitude (rad.s)
                               End SphMap
                            MapB = 	# Second component Mapping
                               Begin CmpMap 	# Compound Mapping
                                  Nin = 3 	# Number of input coordinates
                                  Nout = 2 	# Number of output coordinates
                               IsA Mapping 	# Mapping between coordinate systems
                                  MapA = 	# First component Mapping
                                     Begin MatrixMap 	# Matrix transformation
                                        Nin = 3 	# Number of input coordinates
                                        Invert = 1 	# Mapping inverted
                                     IsA Mapping 	# Mapping between coordinate systems
                                        M0 = -0.013390823453935901 	# Forward matrix value
                                        M1 = 0.98140171074132598 	# Forward matrix value
                                        M2 = 0.19149769711728801 	# Forward matrix value
                                        M3 = 0.068459122667767006 	# Forward matrix value
                                        M4 = 0.19196531497642699 	# Forward matrix value
                                        M5 = -0.97901106549903705 	# Forward matrix value
                                        M6 = -0.99756405025982398 	# Forward matrix value
                                        M7 = 0 	# Forward matrix value
                                        M8 = -0.069756473744125302 	# Forward matrix value
                                        IM0 = -0.013390823453935882 	# Inverse matrix value
                                        IM1 = 0.068459122667767006 	# Inverse matrix value
                                        IM2 = -0.99756405025982453 	# Inverse matrix value
                                        IM3 = 0.98140171074132576 	# Inverse matrix value
                                        IM4 = 0.19196531497642763 	# Inverse matrix value
                                        IM5 = 2.9385028682508244e-17 	# Inverse matrix value
                                        IM6 = 0.19149769711728745 	# Inverse matrix value
                                        IM7 = -0.97901106549903782 	# Inverse matrix value
                                        IM8 = -0.0697564737441254 	# Inverse matrix value
                                        Form = "Full" 	# Matrix storage form
                                     End MatrixMap
                                  MapB = 	# Second component Mapping
                                     Begin SphMap 	# Cartesian to Spherical mapping
                                        Nin = 3 	# Number of input coordinates
                                        Nout = 2 	# Number of output coordinates
                                        Invert = 1 	# Mapping inverted
                                     IsA Mapping 	# Mapping between coordinate systems
                                        UntRd = 1 	# All input vectors have unit length
                                        PlrLg = 4.9055532953491596 	# Polar longitude (rad.s)
                                     End SphMap
                               End CmpMap
                         End CmpMap
                   End CmpMap
                MapB = 	# Second component Mapping
                   Begin CmpMap 	# Compound Mapping
                      Nin = 1 	# Number of input coordinates
                      IsSimp = 1 	# Mapping has been simplified
                   IsA Mapping 	# Mapping between coordinate systems
                      MapA = 	# First component Mapping
                         Begin SpecMap 	# Conversion between spectral coordinate systems
                            Nin = 1 	# Number of input coordinates
                         IsA Mapping 	# Mapping between coordinate systems
                            Nspec = 4 	# Number of conversion steps
                            Spec1 = "LKF2HL" 	# Convert from LSRK to heliocentric frequency
                            Spec1a = 4.9055389995003802 	# RA of source (FK5 J2000, radians)
                            Spec1b = -0.069813170079773196 	# DEC of source (FK5 J2000, radians)
                            Spec1c = 1.0000544114673284 	# Frequency correction factor
                            Spec2 = "HLF2LK" 	# Convert from Heliocentric to LSRK frequency
                            Spec2a = -1.3776320118304248 	# RA of source (FK5 J2000, radians)
                            Spec2b = -0.069813170079773196 	# DEC of source (FK5 J2000, radians)
                            Spec2c = 0.99994559163770247 	# Frequency correction factor
                            Spec3 = "FRTOVL" 	# Convert frequency to rel. velocity
                            Spec3a = 372672509000 	# Rest frequency (Hz)
                            Spec4 = "VLTOVR" 	# Convert relativistic to radio velocity
                         End SpecMap
                      MapB = 	# Second component Mapping
                         Begin ZoomMap 	# Zoom about the origin
                            Nin = 1 	# Number of input coordinates
                         IsA Mapping 	# Mapping between coordinate systems
                            Zoom = 0.001 	# Zoom factor
                         End ZoomMap
                   End CmpMap
             End CmpMap
       End CmpMap
    MapB = 	# Second component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 3 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# First component Mapping
             Begin CmpMap 	# Compound Mapping
                Nin = 3 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                MapA = 	# First component Mapping
                   Begin CmpMap 	# Compound Mapping
                      Nin = 3 	# Number of input coordinates
                      IsSimp = 1 	# Mapping has been simplified
                   IsA Mapping 	# Mapping between coordinate systems
                      MapA = 	# First component Mapping
                         Begin CmpMap 	# Compound Mapping
                            Nin = 3 	# Number of input coordinates
                            IsSimp = 1 	# Mapping has been simplified
                         IsA Mapping 	# Mapping between coordinate systems
                            Series = 0 	# Component Mappings applied in parallel
                            MapA = 	# First component Mapping
                               Begin CmpMap 	# Compound Mapping
                                  Nin = 2 	# Number of input coordinates
                                  IsSimp = 1 	# Mapping has been simplified
                               IsA Mapping 	# Mapping between coordinate systems
                                  InvA = 1 	# First Mapping used in inverse direction
                                  MapA = 	# First component Mapping
                                     Begin SphMap 	# Cartesian to Spherical mapping
                                        Nin = 3 	# Number of input coordinates
                                        Nout = 2 	# Number of output coordinates
                                     IsA Mapping 	# Mapping between coordinate systems
                                        UntRd = 1 	# All input vectors have unit length
                                        PlrLg = 4.9055532953491614 	# Polar longitude (rad.s)
                                     End SphMap
                                  MapB = 	# Second component Mapping
                                     Begin CmpMap 	# Compound Mapping
                                        Nin = 3 	# Number of input coordinates
                                        Nout = 2 	# Number of output coordinates
                                     IsA Mapping 	# Mapping between coordinate systems
                                        InvA = 1 	# First Mapping used in inverse direction
                                        MapA = 	# First component Mapping
                                           Begin MatrixMap 	# Matrix transformation
                                              Nin = 3 	# Number of input coordinates
                                           IsA Mapping 	# Mapping between coordinate systems
                                              M0 = -0.013390823453935894 	# Forward matrix value
                                              M1 = 0.98140171074132587 	# Forward matrix value
                                              M2 = 0.19149769711728762 	# Forward matrix value
                                              M3 = 0.068459122667766978 	# Forward matrix value
                                              M4 = 0.19196531497642721 	# Forward matrix value
                                              M5 = -0.97901106549903749 	# Forward matrix value
                                              M6 = -0.9975640502598242 	# Forward matrix value
                                              M7 = 0 	# Forward matrix value
                                              M8 = -0.06975647374412533 	# Forward matrix value
                                              IM0 = -0.013390823453935894 	# Inverse matrix value
                                              IM1 = 0.068459122667766978 	# Inverse matrix value
                                              IM2 = -0.9975640502598242 	# Inverse matrix value
                                              IM3 = 0.98140171074132587 	# Inverse matrix value
                                              IM4 = 0.19196531497642721 	# Inverse matrix value
                                              IM5 = 0 	# Inverse matrix value
                                              IM6 = 0.19149769711728762 	# Inverse matrix value
                                              IM7 = -0.97901106549903749 	# Inverse matrix value
                                              IM8 = -0.06975647374412533 	# Inverse matrix value
                                              Form = "Full" 	# Matrix storage form
                                           End MatrixMap
                                        MapB = 	# Second component Mapping
                                           Begin SphMap 	# Cartesian to Spherical mapping
                                              Nin = 3 	# Number of input coordinates
                                              Nout = 2 	# Number of output coordinates
                                              Invert = 1 	# Mapping inverted
                                           IsA Mapping 	# Mapping between coordinate systems
                                              UntRd = 1 	# All input vectors have unit length
                                              PlrLg = 0 	# Polar longitude (rad.s)
                                           End SphMap
                                     End CmpMap
                               End CmpMap
                            MapB = 	# Second component Mapping
                               Begin UnitMap 	# Unit (null) Mapping
                                  Nin = 1 	# Number of input coordinates
                               IsA Mapping 	# Mapping between coordinate systems
                               End UnitMap
                         End CmpMap
                      MapB = 	# Second component Mapping
                         Begin CmpMap 	# Compound Mapping
                            Nin = 3 	# Number of input coordinates
                         IsA Mapping 	# Mapping between coordinate systems
                            InvB = 1 	# Second Mapping used in inverse direction
                            MapA = 	# First component Mapping
                               Begin WcsMap 	# FITS-WCS sky projection
                                  Nin = 3 	# Number of input coordinates
                                  Invert = 1 	# Mapping inverted
                               IsA Mapping 	# Mapping between coordinate systems
                                  Type = "TAN" 	# Gnomonic projection
                               End WcsMap
                            MapB = 	# Second component Mapping
                               Begin MatrixMap 	# Matrix transformation
                                  Nin = 3 	# Number of input coordinates
                               IsA Mapping 	# Mapping between coordinate systems
                                  M0 = 0.017453292519943295 	# Forward matrix value
                                  M1 = 0.017453292519943295 	# Forward matrix value
                                  M2 = 1 	# Forward matrix value
                                  IM0 = 57.295779513082323 	# Inverse matrix value
                                  IM1 = 57.295779513082323 	# Inverse matrix value
                                  IM2 = 1 	# Inverse matrix value
                                  Form = "Diagonal" 	# Matrix storage form
                               End MatrixMap
                         End CmpMap
                   End CmpMap
                MapB = 	# Second component Mapping
                   Begin ShiftMap 	# Shift each coordinate axis
                      Nin = 3 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Sft3 = 13.610152711803124 	# Shift for axis 3
                   End ShiftMap
             End CmpMap
          MapB = 	# Second component Mapping
             Begin UnitMap 	# Unit (null) Mapping
                Nin = 3 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
             End UnitMap
       End CmpMap
 End CmpMap
